class Solution(object):
    def minBitwiseArray(self, nums):
        result = []
        for p in nums:
            if p == 2:
                result.append(-1)
            else:
                lb = (p + 1) & -(p + 1)
                result.append(p ^ (lb >> 1))
        return result
